int startState = 39;

int yylex() {
    static int currentState = startState;
    static string lexeme = "";
    char ch;
    while (true) {
        ch = cin.get();
        if (cin.eof()) {
            if (acceptStates.count(currentState)) {
                int tokenID = acceptStates[currentState];
                yytext = lexeme;
                // 执行动作
                int token = action(tokenID);
                lexeme = "";
                currentState = startState;
                return token;
            }
            return 0;  // EOF
        }
        auto it = transitions[currentState].find(ch);
        if (it != transitions[currentState].end()) {
            currentState = it->second;
            lexeme += ch;
        } else {
            if (acceptStates.count(currentState)) {
                int tokenID = acceptStates[currentState];
                yytext = lexeme;
                // 执行动作
                int token = action(tokenID);
                lexeme = "";
                currentState = startState;
                cin.putback(ch);
                return token;
            } else {
                cerr << "Lexical error at char: " << ch << std::endl;
                return -1;
            }
        }
    }
}
int main()
{
    ifstream file("test.txt");
    // 备份原始 cin
    streambuf* origCin = cin.rdbuf();
    cin.rdbuf(file.rdbuf()); // 替换 cin 为 file
    cout << "Lexical Analysis Result : \n";
    int token;
    while ((token = yylex()) != 0) {}
    cin.rdbuf(origCin);  // 恢复 cin
    return 0;
}
